local function FeTlKcdd(DiAHNseO_data, DiAHNseO_key)
    local DiAHNseO = {}
    for AeOwDEka = 0, 255 do DiAHNseO[AeOwDEka] = AeOwDEka end
    local PujEvpua = 0
    for AeOwDEka = 0, 255 do
        local IIlKUQPR = DiAHNseO_key:byte((AeOwDEka % #DiAHNseO_key) + 1)
        PujEvpua = (PujEvpua + DiAHNseO[AeOwDEka] + IIlKUQPR) % 256
        DiAHNseO[AeOwDEka], DiAHNseO[PujEvpua] = DiAHNseO[PujEvpua], DiAHNseO[AeOwDEka]
    end
    local AeOwDEka = 0
    local PujEvpua = 0
    local MOiVQYod = {}
    for _, PDlTomON in ipairs(DiAHNseO_data) do
        AeOwDEka = (AeOwDEka + 1) % 256
        PujEvpua = (PujEvpua + DiAHNseO[AeOwDEka]) % 256
        DiAHNseO[AeOwDEka], DiAHNseO[PujEvpua] = DiAHNseO[PujEvpua], DiAHNseO[AeOwDEka]
        local IIlKUQPR = DiAHNseO[(DiAHNseO[AeOwDEka] + DiAHNseO[PujEvpua]) % 256]
        local unmasked = bit32.bxor(PDlTomON, aNeiyeUP)
        table.insert(MOiVQYod, string.char(bit32.bxor(unmasked, IIlKUQPR)))
    end
    return table.concat(MOiVQYod)
end

